def random_vector(dim: int, seed: int) -> TernaryVector:
    """Generate random ternary vector with values in {-1, 0, +1}."""
    rng = random.Random(seed)
    data = [rng.choice([-1, 0, 1]) for _ in range(dim)]
    return TernaryVector(dimension=dim, data=data)


def bind(a: TernaryVector, b: TernaryVector) -> TernaryVector:
    """Element-wise multiplication (ternary bind)."""
    assert a.dimension == b.dimension
    data = [a.data[i] * b.data[i] for i in range(a.dimension)]
    return TernaryVector(dimension=a.dimension, data=data)


def unbind(bound: TernaryVector, key: TernaryVector) -> TernaryVector:
    """Unbind = bind (self-inverse for ternary multiplication)."""
    return bind(bound, key)


def bundle3(a: TernaryVector, b: TernaryVector, c: TernaryVector) -> TernaryVector:
    """Majority vote of 3 vectors."""
    assert a.dimension == b.dimension == c.dimension
    data = []
    for i in range(a.dimension):
        s = a.data[i] + b.data[i] + c.data[i]
        if s > 0:
            data.append(1)
        elif s < 0:
            data.append(-1)
        else:
            data.append(0)
    return TernaryVector(dimension=a.dimension, data=data)


def cosine_similarity(a: TernaryVector, b: TernaryVector) -> float:
    """Cosine similarity between two ternary vectors."""
    assert a.dimension == b.dimension
    dot = sum(a.data[i] * b.data[i] for i in range(a.dimension))
    norm_a = math.sqrt(sum(x * x for x in a.data))
    norm_b = math.sqrt(sum(x * x for x in b.data))
    if norm_a == 0 or norm_b == 0:
        return 0.0
    return dot / (norm_a * norm_b)


def permute(v: TernaryVector, k: int) -> TernaryVector:
    """Cyclic permutation by k positions."""
    d = v.dimension
    k = k % d
    data = v.data[k:] + v.data[:k]
    return TernaryVector(dimension=d, data=data)


